const cp = require('child_process');
const input = $input.first().json;
const proj = (input.params && input.params.project) || input.project || 'C:/Users/iohan/Documents/ClaudeObsidian/agent-project-template';
const results = {};

try {
  results.drift = cp.execSync('bash scripts/check-drift.sh 2>&1', {cwd: proj, timeout: 30000, encoding: 'utf8'});
} catch(e) {
  results.drift = (e.stdout || '') + (e.stderr || e.message);
}

try {
  const status = cp.execSync('git status --porcelain 2>&1', {cwd: proj, timeout: 5000, encoding: 'utf8'});
  results.uncommitted = status.split('\n').filter(l => l.trim()).length;
  results.branch = cp.execSync('git branch --show-current 2>&1', {cwd: proj, timeout: 5000, encoding: 'utf8'}).trim();
} catch(e) {
  results.git_error = e.message;
}

try {
  const lessons = cp.execSync('grep -c "^### " tasks/lessons.md 2>/dev/null || echo 0', {cwd: proj, timeout: 5000, encoding: 'utf8'}).trim();
  results.lessons_count = parseInt(lessons);
} catch { results.lessons_count = 0; }

results.status = 'complete';
results.project = proj;
results.timestamp = new Date().toISOString();
return [{json: results}];
